def estimate_model_size(layers: list) -> dict:
    MB = 1024 * 1024
    per_layer = []

    for layer in layers:
        ltype = layer['type']
        if ltype == 'linear':
            params = layer['in'] * layer['out']
            if layer.get('bias', True):
                params += layer['out']
        elif ltype == 'embedding':
            params = layer['vocab'] * layer['dim']
        elif ltype == 'conv2d':
            params = layer['in_c'] * layer['out_c'] * layer['k'] * layer['k']
            if layer.get('bias', True):
                params += layer['out_c']
        else:
            raise ValueError(f"Unknown layer type: {ltype!r}")
        per_layer.append(params)

    total = sum(per_layer)
    return {
        'total_params': total,
        'size_fp32_mb': total * 4 / MB,
        'size_fp16_mb': total * 2 / MB,
        'size_int8_mb': total * 1 / MB,
        'per_layer_params': per_layer
    }

